    if (n == 0) return 0L

    // 1. Get the sorted version of nums
    val sortedNums = nums.sorted.toSeq.toVector

    // 2. Find all divisors k of N
    val divisors = (1 to n).filter { n % it == 0 }.toSeq

    var sumK: Long = 0

    // 3. Check each divisor k
    for (k <- divisors) {
      var isValidK = true

      // Iterate through blocks
      var i = 0
      while (i < n) {
        val start = i
        val end = i + k

        // C_i: Original chunk
        val originalChunk = nums.slice(start, end).toSeq

        // S_i: Target chunk (from sorted array)
        val targetChunk = sortedNums.slice(start, end).toSeq

        // Check 1: Multiset equality (Check if sorting C_i yields S_i)
        val sortedOriginalChunk = originalChunk.sorted
        if (sortedOriginalChunk != targetChunk) {
          isValidK = false
          break
        }

        // Check 2: Cyclic Permutation
        if (k > 1) {
          // Count inversions cyclically: C_i[p] > C_i[(p+1) mod k]
          var inversions = 0
          for (p <- 0 until k) {
            val next_p = (p + 1) % k
            if (originalChunk(p) > originalChunk(next_p)) {
              inversions += 1
            }
          }

          // A sequence of length k > 1 is a rotation of a sorted sequence 
          // if and only if it has at most one adjacent inversion (cyclically).
          if (inversions > 1) {
            isValidK = false
            break
          }
        }
        // If k=1, inversions = 0, which is <= 1, so it's always valid.

        i += k
      }

      if (isValidK) {
        sumK += k.toLong
      }
    }

    sumK
  }
